previewCss:
.darma-loader-darma-research-aurora-card-skeleton { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #22c55e); --accent-2: var(--loader-secondary-color, #38bdf8); width: calc(var(--loader-size, 72px) * 2.55); min-width: 160px; padding: 14px; border-radius: 22px; background: linear-gradient(145deg, #121827, #0b1020); box-shadow: inset 0 1px #fff2, 0 18px 40px #02061766; overflow: hidden; position: relative; }
.darma-loader-darma-research-aurora-card-skeleton::before { content: ""; position: absolute; inset: -45%; background: conic-gradient(from 0deg, transparent, var(--accent), var(--accent-2), transparent 45%); animation: darma-loader-darma-research-aurora-card-skeleton-aurora-sweep calc(var(--speed) * 4) linear infinite; opacity: .35; }
.darma-loader-darma-research-aurora-card-skeleton__media, .darma-loader-darma-research-aurora-card-skeleton__row { position: relative; overflow: hidden; background: #293145; border-radius: 14px; z-index: 1; }
.darma-loader-darma-research-aurora-card-skeleton__media { height: calc(var(--loader-size, 72px) * .82); margin-bottom: 14px; }
.darma-loader-darma-research-aurora-card-skeleton__row { height: 11px; margin-top: 10px; width: 100%; }
.darma-loader-darma-research-aurora-card-skeleton__row-lg { width: 82%; }
.darma-loader-darma-research-aurora-card-skeleton__row-sm { width: 55%; }
.darma-loader-darma-research-aurora-card-skeleton__media::after, .darma-loader-darma-research-aurora-card-skeleton__row::after { content: ""; position: absolute; inset: 0; translate: -120% 0; background: linear-gradient(90deg, transparent, #ffffff40, transparent); animation: darma-loader-darma-research-aurora-card-skeleton-aurora-line calc(var(--speed) * 1.45) ease-in-out infinite; }
.darma-loader-darma-research-aurora-card-skeleton__row:nth-of-type(3)::after { animation-delay: .15s; }
.darma-loader-darma-research-aurora-card-skeleton__row:nth-of-type(4)::after { animation-delay: .3s; }
@keyframes darma-loader-darma-research-aurora-card-skeleton-aurora-line { to { translate: 120% 0; } }
@keyframes darma-loader-darma-research-aurora-card-skeleton-aurora-sweep { to { rotate: 360deg; } }

